import random
import math
import heapq
import itertools

def compute_model_placement(gpu_num, models):
    GPU_MEMORY_LIMIT = 80

    def kvpr_for_gpu(gpu_models):
        if not gpu_models:
            return 0.0
        load = sum(m.req_rate / m.slo for m in gpu_models)
        mem = sum(m.model_size for m in gpu_models)
        if mem >= GPU_MEMORY_LIMIT:
            return float('inf')
        denominator = GPU_MEMORY_LIMIT - mem
        if denominator <= 0:
            return float('inf')
        return load / denominator

    def max_kvpr(placement):
        max_val = 0.0
        for i in range(gpu_num):
            val = kvpr_for_gpu(placement.get(i, []))
            if val > max_val:
                max_val = val
        return max_val

    best_placement = None
    best_kvpr = float('inf')

    max_attempts = 20
    for attempt in range(max_attempts):
        random.shuffle(models)
        placement = {i: [] for i in range(gpu_num)}
        gpu_mem = [0] * gpu_num

        for model in models:
            best_gpu = -1
            best_score = float('inf')

            for gid in range(gpu_num):
                if gpu_mem[gid] + model.model_size <= GPU_MEMORY_LIMIT:
                    placement[gid].append(model)
                    gpu_mem[gid] += model.model_size
                    score = max_kvpr(placement)
                    placement[gid].pop()
                    gpu_mem[gid] -= model.model_size

                    if score < best_score:
                        best_score = score
                        best_gpu = gid

            if best_gpu == -1:
                best_gpu = min(range(gpu_num), key=lambda g: gpu_mem[g])

            placement[best_gpu].append(model)
            gpu_mem[best_gpu] += model.model_size

        current_kvpr = max_kvpr(placement)

        max_local_iter = 100
        for _ in range(max_local_iter):
            improved = False

            for i in range(gpu_num):
                for j in range(gpu_num):
                    if i == j:
                        continue
                    if not placement[i] or not placement[j]:
                        continue

                    for mi, model_i in enumerate(placement[i]):
                        for mj, model_j in enumerate(placement[j]):
                            mem_i = gpu_mem[i] - model_i.model_size + model_j.model_size
                            mem_j = gpu_mem[j] - model_j.model_size + model_i.model_size

                            if mem_i > GPU_MEMORY_LIMIT or mem_j > GPU_MEMORY_LIMIT:
                                continue

                            placement[i][mi], placement[j][mj] = placement[j][mj], placement[i][mi]
                            gpu_mem[i] = mem_i
                            gpu_mem[j] = mem_j
                            new_kvpr = max_kvpr(placement)

                            if new_kvpr < current_kvpr:
                                current_kvpr = new_kvpr
                                improved = True
                            else:
                                placement[i][mi], placement[j][mj] = placement[j][mj], placement[i][mi]
                                gpu_mem[i] = mem_i - model_j.model_size + model_i.model_size
                                gpu_mem[j] = mem_j - model_i.model_size + model_j.model_size

            if not improved:
                break

        if current_kvpr < best_kvpr:
            best_kvpr = current_kvpr
            best_placement = {i: list(placement[i]) for i in range(gpu_num)}

    if best_placement is None:
        best_placement = {i: [] for i in range(gpu_num)}
        for model in models:
            gpu_id = min(range(gpu_num), key=lambda g: sum(m.model_size for m in best_placement[g]))
            best_placement[gpu_id].append(model)

    return best_placement

import random
import math
import itertools

def compute_model_placement(gpu_num, models):
    GPU_MEMORY = 80.0

    # Add IDs to models for tracking
    for i, m in enumerate(models):
        m.id = i

    def safe_divide(a, b):
        if abs(b) < 1e-12:
            return float('inf')
        return a / b

    def compute_kvpr(model_list):
        if not model_list:
            return 0.0
        total_pressure = 0.0
        total_size = 0.0
        for m in model_list:
            total_pressure += safe_divide(m.req_rate, m.slo)
            total_size += m.model_size
        remaining = GPU_MEMORY - total_size
        if remaining <= 1e-12:
            return float('inf')
        return safe_divide(total_pressure, remaining)

    def max_kvpr(placement_dict):
        max_val = 0.0
        for gpu_id in range(gpu_num):
            kvpr = compute_kvpr(placement_dict[gpu_id])
            if kvpr > max_val:
                max_val = kvpr
        return max_val

    # Greedy initialization with multiple strategies
    def greedy_initial(strategy='density'):
        placement = {i: [] for i in range(gpu_num)}
        mem_used = [0.0] * gpu_num
        pressure_used = [0.0] * gpu_num

        # Create a copy of models to work with
        models_copy = list(models)

        if strategy == 'density':
            models_copy.sort(key=lambda m: safe_divide(m.req_rate / m.slo, m.model_size) 
                            if m.model_size > 0 else float('inf'), reverse=True)
        elif strategy == 'pressure':
            models_copy.sort(key=lambda m: m.req_rate / m.slo, reverse=True)
        elif strategy == 'size':
            models_copy.sort(key=lambda m: m.model_size, reverse=True)
        elif strategy == 'random':
            random.shuffle(models_copy)
        else:  # balanced
            models_copy.sort(key=lambda m: (m.req_rate / m.slo) * m.model_size, reverse=True)

        for model in models_copy:
            best_gpu = -1
            best_score = float('inf')

            for gpu in range(gpu_num):
                if mem_used[gpu] + model.model_size <= GPU_MEMORY + 1e-9:
                    new_pressure = pressure_used[gpu] + safe_divide(model.req_rate, model.slo)
                    new_mem = mem_used[gpu] + model.model_size
                    remaining = GPU_MEMORY - new_mem

                    if remaining <= 1e-12:
                        kvpr = float('inf')
                    else:
                        kvpr = safe_divide(new_pressure, remaining)

                    # Score balances KVPR and memory utilization
                    score = kvpr * (1.0 + 0.05 * (new_mem / GPU_MEMORY))

                    if score < best_score - 1e-12:
                        best_score = score
                        best_gpu = gpu

            if best_gpu == -1:
                # Fallback: put in GPU with most free space
                best_gpu = max(range(gpu_num), key=lambda g: GPU_MEMORY - mem_used[g])

            placement[best_gpu].append(model)
            mem_used[best_gpu] += model.model_size
            pressure_used[best_gpu] += safe_divide(model.req_rate, model.slo)

        return placement

    # Local search with simulated annealing
    def local_search_annealing(initial_placement, iterations=3000):
        current = {i: list(initial_placement[i]) for i in range(gpu_num)}
        current_kvpr = max_kvpr(current)

        best = {i: list(current[i]) for i in range(gpu_num)}
        best_kvpr = current_kvpr

        temperature = 5.0
        cooling_rate = 0.997

        for iteration in range(iterations):
            # Choose move type
            move_type = random.random()

            if move_type < 0.6:  # Move a model from high to low KVPR GPU
                kvprs = [compute_kvpr(current[g]) for g in range(gpu_num)]
                src = max(range(gpu_num), key=lambda g: kvprs[g])
                dst = min(range(gpu_num), key=lambda g: kvprs[g])

                if current[src] and src != dst:
                    model = random.choice(current[src])
                    dst_mem = sum(m.model_size for m in current[dst])

                    if dst_mem + model.model_size <= GPU_MEMORY + 1e-9:
                        new_placement = {i: list(current[i]) for i in range(gpu_num)}
                        new_placement[src].remove(model)
                        new_placement[dst].append(model)

                        new_kvpr = max_kvpr(new_placement)
                        delta = new_kvpr - current_kvpr

                        if delta < -1e-12 or (temperature > 1e-12 and 
                                           random.random() < math.exp(-delta / temperature)):
                            current = new_placement
                            current_kvpr = new_kvpr

                            if new_kvpr < best_kvpr - 1e-12:
                                best = {i: list(new_placement[i]) for i in range(gpu_num)}
                                best_kvpr = new_kvpr

            elif move_type < 0.9:  # Swap models between two GPUs
                g1, g2 = random.sample(range(gpu_num), 2)
                if current[g1] and current[g2]:
                    m1 = random.choice(current[g1])
                    m2 = random.choice(current[g2])

                    if m1 != m2:
                        mem1 = sum(m.model_size for m in current[g1]) - m1.model_size + m2.model_size
                        mem2 = sum(m.model_size for m in current[g2]) - m2.model_size + m1.model_size

                        if mem1 <= GPU_MEMORY + 1e-9 and mem2 <= GPU_MEMORY + 1e-9:
                            new_placement = {i: list(current[i]) for i in range(gpu_num)}
                            idx1 = new_placement[g1].index(m1)
                            idx2 = new_placement[g2].index(m2)
                            new_placement[g1][idx1], new_placement[g2][idx2] = m2, m1

                            new_kvpr = max_kvpr(new_placement)
                            delta = new_kvpr - current_kvpr

                            if delta < -1e-12 or (temperature > 1e-12 and 
                                               random.random() < math.exp(-delta / temperature)):
                                current = new_placement
                                current_kvpr = new_kvpr

                                if new_kvpr < best_kvpr - 1e-12:
                                    best = {i: list(new_placement[i]) for i in range(gpu_num)}
                                    best_kvpr = new_kvpr

            else:  # Move multiple models
                src = random.randrange(gpu_num)
                dst = random.randrange(gpu_num)
                if src != dst and current[src]:
                    num_to_move = random.randint(1, min(3, len(current[src])))
                    models_to_move = random.sample(current[src], num_to_move)

                    src_mem_after = sum(m.model_size for m in current[src]) - \
                                   sum(m.model_size for m in models_to_move)
                    dst_mem_after = sum(m.model_size for m in current[dst]) + \
                                   sum(m.model_size for m in models_to_move)

                    if dst_mem_after <= GPU_MEMORY + 1e-9:
                        new_placement = {i: list(current[i]) for i in range(gpu_num)}
                        for m in models_to_move:
                            new_placement[src].remove(m)
                            new_placement[dst].append(m)

                        new_kvpr = max_kvpr(new_placement)
                        delta = new_kvpr - current_kvpr

                        if delta < -1e-12 or (temperature > 1e-12 and 
                                           random.random() < math.exp(-delta / temperature)):
                            current = new_placement
                            current_kvpr = new_kvpr

                            if new_kvpr < best_kvpr - 1e-12:
                                best = {i: list(new_placement[i]) for i in range(gpu_num)}
                                best_kvpr = new_kvpr

            # Cool down
            temperature *= cooling_rate

        return best, best_kvpr

    # Hill climbing refinement
    def hill_climbing_refine(solution):
        placement = {i: list(solution[i]) for i in range(gpu_num)}
        improved = True

        while improved:
            improved = False
            kvprs = [compute_kvpr(placement[g]) for g in range(gpu_num)]
            worst_gpu = max(range(gpu_num), key=lambda g: kvprs[g])

            # Try to move models from worst GPU to others
            for model in list(placement[worst_gpu]):
                for target in range(gpu_num):
                    if target == worst_gpu:
                        continue

                    target_mem = sum(m.model_size for m in placement[target])
                    if target_mem + model.model_size <= GPU_MEMORY + 1e-9:
                        # Simulate move
                        temp = {i: list(placement[i]) for i in range(gpu_num)}
                        temp[worst_gpu].remove(model)
                        temp[target].append(model)

                        new_kvpr = max_kvpr(temp)
                        if new_kvpr < kvprs[worst_gpu] - 1e-12:
                            placement = temp
                            improved = True
                            break

                if improved:
                    break

        return placement

    # Multi-start search
    best_overall = None
    best_kvpr_value = float('inf')

    strategies = ['density', 'pressure', 'size', 'balanced', 'random']

    for attempt in range(50):
        if attempt < len(strategies):
            strategy = strategies[attempt]
        else:
            strategy = random.choice(strategies)

        # Shuffle occasionally for diversity
        if random.random() < 0.3:
            random.shuffle(models)

        initial = greedy_initial(strategy)
        solution, kvpr = local_search_annealing(initial, iterations=2000)
        solution = hill_climbing_refine(solution)
        kvpr = max_kvpr(solution)

        if kvpr < best_kvpr_value - 1e-12:
            best_kvpr_value = kvpr
            best_overall = solution

    # Fallback if no valid placement found
    if best_overall is None:
        best_overall = {i: [] for i in range(gpu_num)}
        for model in models:
            # Put each model in GPU with most free space
            gpu_id = max(range(gpu_num), key=lambda g: GPU_MEMORY - 
                        sum(m.model_size for m in best_overall[g]))
            best_overall[gpu_id].append(model)

    # Remove IDs before returning
    for model in models:
        if hasattr(model, 'id'):
            delattr(model, 'id')

    return best_overall

import random
import math
import itertools

def compute_model_placement(gpu_num, models):
    MEM_LIMIT = 80.0

    # Add IDs to models for tracking
    for idx, m in enumerate(models):
        m.id = idx
        m.pressure = m.req_rate / m.slo if m.slo != 0 else 0.0
        m.density = m.pressure / m.model_size if m.model_size > 0 else float('inf')

    def gpu_metrics(model_list):
        total_size = sum(m.model_size for m in model_list)
        total_pressure = sum(m.pressure for m in model_list)
        remaining = MEM_LIMIT - total_size
        if remaining <= 1e-9:
            return float('inf'), total_size, total_pressure
        return total_pressure / remaining, total_size, total_pressure

    def max_kvpr(placement):
        max_val = 0.0
        for gpu_id in range(gpu_num):
            kvpr, _, _ = gpu_metrics(placement[gpu_id])
            max_val = max(max_val, kvpr)
        return max_val

    # Greedy initialization with multiple strategies
    def greedy_initial(strategy='balanced'):
        placement = {i: [] for i in range(gpu_num)}
        mem_used = [0.0] * gpu_num
        pressure_used = [0.0] * gpu_num

        if strategy == 'density':
            sorted_models = sorted(models, key=lambda m: m.density, reverse=True)
        elif strategy == 'pressure':
            sorted_models = sorted(models, key=lambda m: m.pressure, reverse=True)
        elif strategy == 'size':
            sorted_models = sorted(models, key=lambda m: m.model_size, reverse=True)
        else:  # balanced
            sorted_models = sorted(models, key=lambda m: m.pressure * m.model_size, reverse=True)

        for model in sorted_models:
            best_gpu = -1
            best_score = float('inf')

            for g in range(gpu_num):
                if mem_used[g] + model.model_size <= MEM_LIMIT:
                    new_pressure = pressure_used[g] + model.pressure
                    new_mem = mem_used[g] + model.model_size
                    remaining = MEM_LIMIT - new_mem
                    if remaining <= 1e-9:
                        kvpr = float('inf')
                    else:
                        kvpr = new_pressure / remaining

                    # Score balances KVPR and memory utilization
                    score = kvpr * (1.0 + 0.05 * (new_mem / MEM_LIMIT))

                    if score < best_score:
                        best_score = score
                        best_gpu = g

            if best_gpu == -1:
                best_gpu = max(range(gpu_num), key=lambda g: MEM_LIMIT - mem_used[g])

            placement[best_gpu].append(model)
            mem_used[best_gpu] += model.model_size
            pressure_used[best_gpu] += model.pressure

        return placement

    # Simulated annealing with adaptive moves
    def simulated_annealing(initial_placement, max_iter=8000):
        current = {g: list(initial_placement[g]) for g in range(gpu_num)}
        current_kvpr = max_kvpr(current)

        best = {g: list(current[g]) for g in range(gpu_num)}
        best_kvpr = current_kvpr

        temp = 10.0
        cooling = 0.997
        no_improve = 0

        for iter_num in range(max_iter):
            if no_improve > 600:
                break

            # Adaptive move selection
            r = random.random()
            new_placement = None

            if r < 0.5:  # Move from high to low KVPR GPU
                kvprs = [gpu_metrics(current[g])[0] for g in range(gpu_num)]
                src = max(range(gpu_num), key=lambda g: kvprs[g])
                dst = min(range(gpu_num), key=lambda g: kvprs[g])

                if current[src] and src != dst:
                    model = random.choice(current[src])
                    dst_mem = sum(m.model_size for m in current[dst])

                    if dst_mem + model.model_size <= MEM_LIMIT:
                        new_placement = {g: list(current[g]) for g in range(gpu_num)}
                        new_placement[src].remove(model)
                        new_placement[dst].append(model)

            elif r < 0.8:  # Swap between GPUs
                g1, g2 = random.sample(range(gpu_num), 2)
                if current[g1] and current[g2]:
                    m1 = random.choice(current[g1])
                    m2 = random.choice(current[g2])

                    mem1 = sum(m.model_size for m in current[g1]) - m1.model_size + m2.model_size
                    mem2 = sum(m.model_size for m in current[g2]) - m2.model_size + m1.model_size

                    if mem1 <= MEM_LIMIT and mem2 <= MEM_LIMIT:
                        new_placement = {g: list(current[g]) for g in range(gpu_num)}
                        idx1 = new_placement[g1].index(m1)
                        idx2 = new_placement[g2].index(m2)
                        new_placement[g1][idx1], new_placement[g2][idx2] = m2, m1

            else:  # Multi-model move
                src = random.randrange(gpu_num)
                dst = random.randrange(gpu_num)
                if src != dst and current[src]:
                    num_to_move = min(3, len(current[src]))
                    if num_to_move > 0:
                        models_to_move = random.sample(current[src], num_to_move)
                        total_size = sum(m.model_size for m in models_to_move)
                        dst_mem = sum(m.model_size for m in current[dst])

                        if dst_mem + total_size <= MEM_LIMIT:
                            new_placement = {g: list(current[g]) for g in range(gpu_num)}
                            for m in models_to_move:
                                new_placement[src].remove(m)
                                new_placement[dst].append(m)

            if new_placement:
                new_kvpr = max_kvpr(new_placement)
                delta = new_kvpr - current_kvpr

                # Accept improving moves, and sometimes accept worse moves based on temperature
                if delta < -1e-12 or (temp > 1e-12 and random.random() < math.exp(-delta / temp)):
                    current = new_placement
                    current_kvpr = new_kvpr

                    if new_kvpr < best_kvpr - 1e-12:
                        best = {g: list(new_placement[g]) for g in range(gpu_num)}
                        best_kvpr = new_kvpr
                        no_improve = 0
                    else:
                        no_improve += 1
                else:
                    no_improve += 1
            else:
                no_improve += 1

            temp *= cooling

        return best, best_kvpr

    # Deterministic refinement
    def refine_solution(solution):
        placement = {g: list(solution[g]) for g in range(gpu_num)}
        improved = True

        while improved:
            improved = False
            kvprs = [gpu_metrics(placement[g])[0] for g in range(gpu_num)]
            max_gpu = max(range(gpu_num), key=lambda g: kvprs[g])

            # Try moving each model from the max KVPR GPU
            for model in list(placement[max_gpu]):
                for target in range(gpu_num):
                    if target == max_gpu:
                        continue

                    target_mem = sum(m.model_size for m in placement[target])
                    if target_mem + model.model_size <= MEM_LIMIT:
                        temp = {g: list(placement[g]) for g in range(gpu_num)}
                        temp[max_gpu].remove(model)
                        temp[target].append(model)

                        new_kvpr = max_kvpr(temp)
                        if new_kvpr < kvprs[max_gpu] - 1e-12:
                            placement = temp
                            improved = True
                            break

                if improved:
                    break

        return placement

    # Multi-start optimization
    best_solution = None
    best_score = float('inf')

    strategies = ['density', 'pressure', 'size', 'balanced']

    for attempt in range(40):
        if attempt < len(strategies):
            strategy = strategies[attempt]
        else:
            strategy = random.choice(strategies)
            random.shuffle(models)

        initial = greedy_initial(strategy)
        solution, score = simulated_annealing(initial)
        solution = refine_solution(solution)
        score = max_kvpr(solution)

        if score < best_score - 1e-12:
            best_score = score
            best_solution = solution

    # Fallback placement if needed
    if best_solution is None:
        best_solution = {i: [] for i in range(gpu_num)}
        for model in models:
            gpu_id = min(range(gpu_num), key=lambda g: sum(m.model_size for m in best_solution[g]))
            best_solution[gpu_id].append(model)

    # Remove ID attribute to match expected output format
    for model in models:
        if hasattr(model, 'id'):
            delattr(model, 'id')
        if hasattr(model, 'pressure'):
            delattr(model, 'pressure')
        if hasattr(model, 'density'):
            delattr(model, 'density')

    return best_solution

import random
