def compute_model_placement(gpu_num, models):
    GPU_MEMORY = 80

    def gpu_kvpr(model_list):
        if not model_list:
            return 0.0
        total_load = sum(m.req_rate / m.slo for m in model_list)
        total_mem = sum(m.model_size for m in model_list)
        remaining = GPU_MEMORY - total_mem
        if remaining <= 0:
            return float('inf')
        return total_load / remaining

    def max_kvpr(placement):
        max_val = 0.0
        for gpu_id in range(gpu_num):
            kvpr = gpu_kvpr(placement[gpu_id])
            if kvpr > max_val:
                max_val = kvpr
        return max_val

    for model in models:
        model.pressure = model.req_rate / model.slo
        model.density = model.pressure / model.model_size if model.model_size > 0 else float('inf')

    best_placement = None
    best_kvpr = float('inf')

    attempts = 20
    for attempt in range(attempts):
        if attempt == 0:
            sorted_models = sorted(models, key=lambda m: m.density, reverse=True)
        elif attempt < 5:
            sorted_models = sorted(models, key=lambda m: m.pressure, reverse=True)
        else:
            random.shuffle(models)
            sorted_models = models

        placement = {i: [] for i in range(gpu_num)}
        mem_used = [0] * gpu_num

        for model in sorted_models:
            candidates = []
            for gpu_id in range(gpu_num):
                if mem_used[gpu_id] + model.model_size <= GPU_MEMORY:
                    placement[gpu_id].append(model)
                    kvpr = gpu_kvpr(placement[gpu_id])
                    placement[gpu_id].pop()
                    candidates.append((kvpr, -mem_used[gpu_id], gpu_id))

            if candidates:
                _, _, best_gpu = min(candidates)
            else:
                best_gpu = min(range(gpu_num), key=lambda g: mem_used[g])

            placement[best_gpu].append(model)
            mem_used[best_gpu] += model.model_size

        current_placement = {g: list(placement[g]) for g in range(gpu_num)}
        current_kvpr = max_kvpr(current_placement)

        temperature = 10.0
        cooling_rate = 0.9997
        iterations = 20000

        for _ in range(iterations):
            if temperature < 1e-8:
                break

            src_gpu = max(range(gpu_num), key=lambda g: gpu_kvpr(current_placement[g]))
            if not current_placement[src_gpu]:
                break

            op = random.random()
            new_placement = None

            if op < 0.7:
                model_idx = random.randrange(len(current_placement[src_gpu]))
                model_to_move = current_placement[src_gpu][model_idx]

                dst_gpu = min(range(gpu_num), key=lambda g: gpu_kvpr(current_placement[g]))
                if dst_gpu == src_gpu:
                    dst_gpu = random.randrange(gpu_num)

                dst_mem = sum(m.model_size for m in current_placement[dst_gpu])
                if dst_mem + model_to_move.model_size <= GPU_MEMORY:
                    new_placement = {g: list(current_placement[g]) for g in range(gpu_num)}
                    new_placement[src_gpu].pop(model_idx)
                    new_placement[dst_gpu].append(model_to_move)

            elif op < 0.9:
                gpu1, gpu2 = random.sample(range(gpu_num), 2)
                if not current_placement[gpu1] or not current_placement[gpu2]:
                    continue

                idx1 = random.randrange(len(current_placement[gpu1]))
                idx2 = random.randrange(len(current_placement[gpu2]))
                m1 = current_placement[gpu1][idx1]
                m2 = current_placement[gpu2][idx2]

                mem1 = sum(m.model_size for m in current_placement[gpu1]) - m1.model_size + m2.model_size
                mem2 = sum(m.model_size for m in current_placement[gpu2]) - m2.model_size + m1.model_size

                if mem1 <= GPU_MEMORY and mem2 <= GPU_MEMORY:
                    new_placement = {g: list(current_placement[g]) for g in range(gpu_num)}
                    new_placement[gpu1][idx1] = m2
                    new_placement[gpu2][idx2] = m1

            if new_placement:
                new_kvpr = max_kvpr(new_placement)
                delta = new_kvpr - current_kvpr

                if delta < 0 or random.random() < math.exp(-delta / temperature):
                    current_placement = new_placement
                    current_kvpr = new_kvpr

                    if current_kvpr < best_kvpr:
                        best_kvpr = current_kvpr
                        best_placement = {g: list(current_placement[g]) for g in range(gpu_num)}

            temperature *= cooling_rate

        if current_kvpr < best_kvpr:
            best_kvpr = current_kvpr
            best_placement = {g: list(current_placement[g]) for g in range(gpu_num)}

    if best_placement is None:
        best_placement = {i: [] for i in range(gpu_num)}
        for model in models:
            gpu_id = min(range(gpu_num), key=lambda g: sum(m.model_size for m in best_placement[g]))
            best_placement[gpu_id].append(model)

    final_improvement = True
    while final_improvement:
        final_improvement = False
        kvpr_values = [gpu_kvpr(best_placement[g]) for g in range(gpu_num)]
        max_gpu = max(range(gpu_num), key=lambda g: kvpr_values[g])

        for idx, model in enumerate(best_placement[max_gpu]):
            for target_gpu in range(gpu_num):
                if target_gpu == max_gpu:
                    continue

                target_mem = sum(m.model_size for m in best_placement[target_gpu])
                if target_mem + model.model_size <= GPU_MEMORY:
                    temp_placement = {g: list(best_placement[g]) for g in range(gpu_num)}
                    temp_placement[max_gpu].pop(idx)
                    temp_placement[target_gpu].append(model)

                    new_kvpr = max_kvpr(temp_placement)
                    if new_kvpr < best_kvpr:
                        best_placement = temp_placement
                        best_kvpr = new_kvpr
                        final_improvement = True
                        break

            if final_improvement:
                break

    return best_placement

def compute_model_placement(gpu_num, models):
    GPU_MEMORY_LIMIT = 80

    # Precompute model characteristics
    model_data = []
    for m in models:
        load = m.req_rate / m.slo
        density = load / m.model_size if m.model_size > 0 else float('inf')
        model_data.append({
            'obj': m,
            'size': m.model_size,
            'load': load,
            'density': density
        })

    # Helper functions
    def compute_gpu_state(assignment):
        """Compute memory usage and load for each GPU given assignment"""
        mem_used = [0] * gpu_num
        load_used = [0.0] * gpu_num
        for gpu_id, model_list in assignment.items():
            for model in model_list:
                for md in model_data:
                    if md['obj'] is model:
                        mem_used[gpu_id] += md['size']
                        load_used[gpu_id] += md['load']
                        break
        return mem_used, load_used

    def compute_kvpr(mem, load):
        """Compute KVPR for a GPU"""
        remaining = GPU_MEMORY_LIMIT - mem
        if remaining <= 0:
            return float('inf')
        return load / remaining

    def compute_max_kvpr(assignment):
        """Compute maximum KVPR across all GPUs"""
        mem_used, load_used = compute_gpu_state(assignment)
        max_val = 0
        for g in range(gpu_num):
            kvpr = compute_kvpr(mem_used[g], load_used[g])
            if kvpr > max_val:
                max_val = kvpr
        return max_val

    # Multi-start simulated annealing with gradient guidance
    best_assignment = None
    best_kvpr = float('inf')

    for start in range(30):  # Multiple starting points
        # Initialize random feasible placement
        current = {i: [] for i in range(gpu_num)}
        mem_used = [0] * gpu_num
        load_used = [0.0] * gpu_num

        # Shuffle models
        shuffled_data = model_data[:]
        import random
        random.shuffle(shuffled_data)

        # Greedy initial placement: place each model to minimize immediate max KVPR increase
        for md in shuffled_data:
            best_gpu = -1
            best_increase = float('inf')

            for g in range(gpu_num):
                if mem_used[g] + md['size'] <= GPU_MEMORY_LIMIT:
                    # Calculate potential new KVPR for this GPU
                    new_mem = mem_used[g] + md['size']
                    new_load = load_used[g] + md['load']
                    new_kvpr = compute_kvpr(new_mem, new_load)

                    # Find maximum KVPR across all GPUs if we place here
                    temp_max = new_kvpr
                    for other_g in range(gpu_num):
                        if other_g != g:
                            kvpr_other = compute_kvpr(mem_used[other_g], load_used[other_g])
                            if kvpr_other > temp_max:
                                temp_max = kvpr_other

                    if temp_max < best_increase:
                        best_increase = temp_max
                        best_gpu = g

            if best_gpu == -1:  # Shouldn't happen with valid input
                # Fallback to GPU with most free memory
                best_gpu = max(range(gpu_num), key=lambda g: GPU_MEMORY_LIMIT - mem_used[g])

            current[best_gpu].append(md['obj'])
            mem_used[best_gpu] += md['size']
            load_used[best_gpu] += md['load']

        # Simulated annealing with gradient-guided moves
        import math
        temperature = 1.0
        cooling_rate = 0.95
        current_kvpr = compute_max_kvpr(current)

        for iteration in range(200):
            # Generate candidate moves
            candidates = []

            # Move operations: move a model from high-KVPR GPU to low-KVPR GPU
            mem_used, load_used = compute_gpu_state(current)
            kvprs = [compute_kvpr(mem_used[g], load_used[g]) for g in range(gpu_num)]
            max_gpu = max(range(gpu_num), key=lambda g: kvprs[g])

            if current[max_gpu]:
                # Try moving each model from max_gpu
                for model_idx, model in enumerate(current[max_gpu]):
                    for md in model_data:
                        if md['obj'] is model:
                            model_info = md
                            break

                    for target_gpu in range(gpu_num):
                        if target_gpu == max_gpu:
                            continue

                        if mem_used[target_gpu] + model_info['size'] <= GPU_MEMORY_LIMIT:
                            # Calculate new KVPRs
                            new_mem_max = mem_used[max_gpu] - model_info['size']
                            new_load_max = load_used[max_gpu] - model_info['load']
                            new_kvpr_max = compute_kvpr(new_mem_max, new_load_max)

                            new_mem_target = mem_used[target_gpu] + model_info['size']
                            new_load_target = load_used[target_gpu] + model_info['load']
                            new_kvpr_target = compute_kvpr(new_mem_target, new_load_target)

                            # Find new maximum
                            new_max = max(new_kvpr_max, new_kvpr_target)
                            for g in range(gpu_num):
                                if g not in (max_gpu, target_gpu):
                                    if kvprs[g] > new_max:
                                        new_max = kvprs[g]

                            improvement = current_kvpr - new_max
                            if improvement > 0:
                                candidates.append(('move', improvement, max_gpu, model_idx, target_gpu))

            # Swap operations
            for gpu1 in range(gpu_num):
                if not current[gpu1]:
                    continue
                for gpu2 in range(gpu1 + 1, gpu_num):
                    if not current[gpu2]:
                        continue

                    for idx1, model1 in enumerate(current[gpu1]):
                        for md in model_data:
                            if md['obj'] is model1:
                                info1 = md
                                break

                        for idx2, model2 in enumerate(current[gpu2]):
                            for md in model_data:
                                if md['obj'] is model2:
                                    info2 = md
                                    break

                            # Check if swap is feasible
                            new_mem1 = mem_used[gpu1] - info1['size'] + info2['size']
                            new_mem2 = mem_used[gpu2] - info2['size'] + info1['size']

                            if new_mem1 <= GPU_MEMORY_LIMIT and new_mem2 <= GPU_MEMORY_LIMIT:
                                # Calculate new loads and KVPRs
                                new_load1 = load_used[gpu1] - info1['load'] + info2['load']
                                new_load2 = load_used[gpu2] - info2['load'] + info1['load']

                                new_kvpr1 = compute_kvpr(new_mem1, new_load1)
                                new_kvpr2 = compute_kvpr(new_mem2, new_load2)

                                # Find new maximum
                                new_max = max(new_kvpr1, new_kvpr2)
                                for g in range(gpu_num):
                                    if g not in (gpu1, gpu2):
                                        if kvprs[g] > new_max:
                                            new_max = kvprs[g]

                                improvement = current_kvpr - new_max
                                if improvement > 0:
                                    candidates.append(('swap', improvement, gpu1, idx1, gpu2, idx2))

            # Choose and apply best move, or accept worse move with probability
            if candidates:
                candidates.sort(key=lambda x: x[1], reverse=True)
                best_move = candidates[0]

                if best_move[1] > 0 or random.random() < math.exp(best_move[1] / temperature):
                    if best_move[0] == 'move':
                        _, _, src_gpu, src_idx, dst_gpu = best_move
                        model = current[src_gpu].pop(src_idx)
                        current[dst_gpu].append(model)
                    else:  # swap
                        _, _, gpu1, idx1, gpu2, idx2 = best_move
                        model1 = current[gpu1][idx1]
                        model2 = current[gpu2][idx2]
                        current[gpu1][idx1] = model2
                        current[gpu2][idx2] = model1

                    current_kvpr = compute_max_kvpr(current)

            # Cool down
            temperature *= cooling_rate

        # Final greedy refinement
        for refinement in range(50):
            improved = False
            mem_used, load_used = compute_gpu_state(current)
            kvprs = [compute_kvpr(mem_used[g], load_used[g]) for g in range(gpu_num)]

            # Try all possible single model moves
            for src_gpu in range(gpu_num):
                for dst_gpu in range(gpu_num):
                    if src_gpu == dst_gpu:
                        continue

                    for model_idx, model in enumerate(current[src_gpu]):
                        for md in model_data:
                            if md['obj'] is model:
                                model_info = md
                                break

                        if mem_used[dst_gpu] + model_info['size'] <= GPU_MEMORY_LIMIT:
                            # Calculate new state
                            new_mem_src = mem_used[src_gpu] - model_info['size']
                            new_load_src = load_used[src_gpu] - model_info['load']
                            new_kvpr_src = compute_kvpr(new_mem_src, new_load_src)

                            new_mem_dst = mem_used[dst_gpu] + model_info['size']
                            new_load_dst = load_used[dst_gpu] + model_info['load']
                            new_kvpr_dst = compute_kvpr(new_mem_dst, new_load_dst)

                            # Check if max KVPR improves
                            old_max = max(kvprs[src_gpu], kvprs[dst_gpu])
                            new_max = max(new_kvpr_src, new_kvpr_dst)
                            for g in range(gpu_num):
                                if g not in (src_gpu, dst_gpu):
                                    if kvprs[g] > old_max:
                                        old_max = kvprs[g]
                                    if kvprs[g] > new_max:
                                        new_max = kvprs[g]

                            if new_max < old_max - 1e-9:
                                # Make the move
                                model = current[src_gpu].pop(model_idx)
                                current[dst_gpu].append(model)
                                improved = True
                                break
                    if improved:
                        break
                if improved:
                    break

        # Update best solution
        final_kvpr = compute_max_kvpr(current)
        if final_kvpr < best_kvpr - 1e-9:
            best_kvpr = final_kvpr
            best_assignment = {k: v[:] for k, v in current.items()}

    # Ensure we return a valid assignment
    if best_assignment is None:
        # Fallback: distribute models evenly by size
        best_assignment = {i: [] for i in range(gpu_num)}
        mem_used = [0] * gpu_num

        # Sort models by size (largest first)
        sorted_models = sorted(models, key=lambda m: m.model_size, reverse=True)

        for model in sorted_models:
            # Find GPU with most free memory
            best_gpu = max(range(gpu_num), key=lambda g: GPU_MEMORY_LIMIT - mem_used[g])
            best_assignment[best_gpu].append(model)
            mem_used[best_gpu] += model.model_size

    return best_assignment

