def compute_model_placement(gpu_num, models):
    GPU_MEMORY_LIMIT = 80

    # Precompute model properties
    model_data = []
    for m in models:
        load = m.req_rate / m.slo
        density = load / m.model_size if m.model_size > 0 else float('inf')
        model_data.append({
            'obj': m,
            'size': m.model_size,
            'load': load,
            'density': density
        })

    def calculate_gpu_kvpr(gpu_models):
        total_load = sum(m['load'] for m in gpu_models)
        total_size = sum(m['size'] for m in gpu_models)
        if total_size >= GPU_MEMORY_LIMIT:
            return float('inf')
        remaining = GPU_MEMORY_LIMIT - total_size
        return total_load / remaining if remaining > 0 else float('inf')

    def calculate_max_kvpr(placement):
        max_val = 0
        for gpu_id in range(gpu_num):
            max_val = max(max_val, calculate_gpu_kvpr(placement[gpu_id]))
        return max_val

    # Helper for memory usage
    def get_mem_used(placement):
        return [sum(m['size'] for m in placement[gpu_id]) for gpu_id in range(gpu_num)]

    best_placement = None
    best_score = float('inf')

    # Multi-start with different initializations
    for start in range(20):
        random.seed(start)

        # Initial greedy placement
        placement = {i: [] for i in range(gpu_num)}
        shuffled_models = list(model_data)
        random.shuffle(shuffled_models)

        for model in shuffled_models:
            best_gpu = -1
            best_increase = float('inf')

            for gpu_id in range(gpu_num):
                mem_used = sum(m['size'] for m in placement[gpu_id])
                if mem_used + model['size'] <= GPU_MEMORY_LIMIT:
                    # Calculate current KVPR for this GPU
                    old_kvpr = calculate_gpu_kvpr(placement[gpu_id])
                    placement[gpu_id].append(model)
                    new_kvpr = calculate_gpu_kvpr(placement[gpu_id])
                    placement[gpu_id].pop()

                    kvpr_increase = new_kvpr - old_kvpr
                    if kvpr_increase < best_increase:
                        best_increase = kvpr_increase
                        best_gpu = gpu_id

            if best_gpu == -1:
                # Fallback: most free space
                best_gpu = max(range(gpu_num), 
                             key=lambda g: GPU_MEMORY_LIMIT - sum(m['size'] for m in placement[g]))

            placement[best_gpu].append(model)

        # Local search with simulated annealing
        current_placement = {g: list(placement[g]) for g in range(gpu_num)}
        current_mem = get_mem_used(current_placement)
        current_score = calculate_max_kvpr(current_placement)

        temp = 1.0
        cooling = 0.995
        iterations = 2000

        for _ in range(iterations):
            if temp < 1e-6:
                break

            # Choose random operation: move or swap
            if random.random() < 0.7:  # Move operation (70% chance)
                # Find non-empty GPU
                non_empty = [g for g in range(gpu_num) if current_placement[g]]
                if not non_empty:
                    continue
                src = random.choice(non_empty)
                if not current_placement[src]:
                    continue

                model_idx = random.randrange(len(current_placement[src]))
                model = current_placement[src][model_idx]

                # Try all possible destinations
                for dst in range(gpu_num):
                    if dst == src:
                        continue
                    if current_mem[dst] + model['size'] <= GPU_MEMORY_LIMIT:
                        # Create new placement
                        new_placement = {g: list(current_placement[g]) for g in range(gpu_num)}
                        new_placement[src].pop(model_idx)
                        new_placement[dst].append(model)

                        new_score = calculate_max_kvpr(new_placement)
                        delta = new_score - current_score

                        if delta < 0 or random.random() < math.exp(-delta / temp):
                            current_placement = new_placement
                            current_mem = get_mem_used(current_placement)
                            current_score = new_score
                            break
            else:  # Swap operation (30% chance)
                # Find two different GPUs with models
                gpu_pairs = list(itertools.combinations(range(gpu_num), 2))
                random.shuffle(gpu_pairs)

                for gpu1, gpu2 in gpu_pairs:
                    if not current_placement[gpu1] or not current_placement[gpu2]:
                        continue

                    idx1 = random.randrange(len(current_placement[gpu1]))
                    idx2 = random.randrange(len(current_placement[gpu2]))
                    model1 = current_placement[gpu1][idx1]
                    model2 = current_placement[gpu2][idx2]

                    # Check memory constraints
                    new_mem1 = current_mem[gpu1] - model1['size'] + model2['size']
                    new_mem2 = current_mem[gpu2] - model2['size'] + model1['size']

                    if new_mem1 <= GPU_MEMORY_LIMIT and new_mem2 <= GPU_MEMORY_LIMIT:
                        new_placement = {g: list(current_placement[g]) for g in range(gpu_num)}
                        new_placement[gpu1][idx1], new_placement[gpu2][idx2] = new_placement[gpu2][idx2], new_placement[gpu1][idx1]

                        new_score = calculate_max_kvpr(new_placement)
                        delta = new_score - current_score

                        if delta < 0 or random.random() < math.exp(-delta / temp):
                            current_placement = new_placement
                            current_mem = get_mem_used(current_placement)
                            current_score = new_score
                        break

            temp *= cooling

        # Update best solution
        if current_score < best_score:
            best_score = current_score
            best_placement = current_placement

    # Convert back to original model objects
    result = {i: [] for i in range(gpu_num)}
    if best_placement:
        for gpu_id in range(gpu_num):
            for model_dict in best_placement[gpu_id]:
                result[gpu_id].append(model_dict['obj'])
    else:
        # Fallback assignment
        for model_dict in model_data:
            best_gpu = min(range(gpu_num), 
                          key=lambda g: calculate_gpu_kvpr(result[g] + [model_dict]))
            result[best_gpu].append(model_dict['obj'])

    return result

