def compute_model_placement(gpu_num, models):
    GPU_MEMORY = 80

    def kvpr_for_gpu(gpu_models):
        if not gpu_models:
            return 0.0
        load = sum(m.req_rate / m.slo for m in gpu_models)
        mem = sum(m.model_size for m in gpu_models)
        if mem >= GPU_MEMORY:
            return float('inf')
        return load / (GPU_MEMORY - mem)

    def compute_pressure_score(model):
        return model.req_rate / model.slo

    models_sorted = sorted(models, key=lambda m: compute_pressure_score(m) / m.model_size if m.model_size > 0 else float('inf'), reverse=True)

    best_placement = None
    best_kvpr = float('inf')

    for iteration in range(50):
        placement = {i: [] for i in range(gpu_num)}
        mem_used = [0] * gpu_num

        random.shuffle(models_sorted)

        for model in models_sorted:
            best_gpu = -1
            best_increase = float('inf')
            best_mem_remaining = -1

            for gpu in range(gpu_num):
                if mem_used[gpu] + model.model_size <= GPU_MEMORY:
                    current_load = sum(m.req_rate / m.slo for m in placement[gpu])
                    current_mem = mem_used[gpu]

                    new_load = current_load + model.req_rate / model.slo
                    new_mem = current_mem + model.model_size
                    new_kvpr = new_load / (GPU_MEMORY - new_mem) if GPU_MEMORY > new_mem else float('inf')

                    mem_remaining = GPU_MEMORY - new_mem

                    if new_kvpr < best_increase or (abs(new_kvpr - best_increase) < 1e-9 and mem_remaining > best_mem_remaining):
                        best_increase = new_kvpr
                        best_gpu = gpu
                        best_mem_remaining = mem_remaining

            if best_gpu == -1:
                best_gpu = min(range(gpu_num), key=lambda g: mem_used[g])

            placement[best_gpu].append(model)
            mem_used[best_gpu] += model.model_size

        current_kvpr = max(kvpr_for_gpu(placement[g]) for g in range(gpu_num))

        for local_search_iter in range(200):
            improved = False

            kvpr_per_gpu = [kvpr_for_gpu(placement[g]) for g in range(gpu_num)]
            worst_gpu = max(range(gpu_num), key=lambda g: kvpr_per_gpu[g])

            if not placement[worst_gpu]:
                break

            worst_models = placement[worst_gpu].copy()
            random.shuffle(worst_models)

            for model in worst_models:
                best_target = -1
                best_improvement = 0

                for target in range(gpu_num):
                    if target == worst_gpu:
                        continue
                    if mem_used[target] + model.model_size <= GPU_MEMORY:
                        old_max = max(kvpr_per_gpu[worst_gpu], kvpr_per_gpu[target])

                        new_worst_kvpr = kvpr_for_gpu([m for m in placement[worst_gpu] if m != model])
                        new_target_kvpr = kvpr_for_gpu(placement[target] + [model])

                        new_max = max(new_worst_kvpr, new_target_kvpr, 
                                     max(kvpr_per_gpu[g] for g in range(gpu_num) if g not in [worst_gpu, target]))

                        improvement = old_max - new_max

                        if improvement > best_improvement + 1e-9:
                            best_improvement = improvement
                            best_target = target

                if best_target != -1:
                    placement[worst_gpu].remove(model)
                    placement[best_target].append(model)
                    mem_used[worst_gpu] -= model.model_size
                    mem_used[best_target] += model.model_size

                    kvpr_per_gpu[worst_gpu] = kvpr_for_gpu(placement[worst_gpu])
                    kvpr_per_gpu[best_target] = kvpr_for_gpu(placement[best_target])
                    current_kvpr = max(kvpr_per_gpu)
                    improved = True
                    break

            if improved:
                continue

            gpus = list(range(gpu_num))
            random.shuffle(gpus)

            for i in range(len(gpus)):
                for j in range(i+1, len(gpus)):
                    g1, g2 = gpus[i], gpus[j]
                    if not placement[g1] or not placement[g2]:
                        continue

                    for m1 in placement[g1]:
                        for m2 in placement[g2]:
                            if (mem_used[g1] - m1.model_size + m2.model_size <= GPU_MEMORY and
                                mem_used[g2] - m2.model_size + m1.model_size <= GPU_MEMORY):

                                old_max = max(kvpr_per_gpu[g1], kvpr_per_gpu[g2])

                                placement[g1].remove(m1)
                                placement[g1].append(m2)
                                placement[g2].remove(m2)
                                placement[g2].append(m1)

                                new_g1_kvpr = kvpr_for_gpu(placement[g1])
                                new_g2_kvpr = kvpr_for_gpu(placement[g2])

                                new_max = max(new_g1_kvpr, new_g2_kvpr, 
                                             max(kvpr_per_gpu[g] for g in range(gpu_num) if g not in [g1, g2]))

                                if new_max < old_max - 1e-9:
                                    mem_used[g1] = mem_used[g1] - m1.model_size + m2.model_size
                                    mem_used[g2] = mem_used[g2] - m2.model_size + m1.model_size
                                    kvpr_per_gpu[g1] = new_g1_kvpr
                                    kvpr_per_gpu[g2] = new_g2_kvpr
                                    current_kvpr = new_max
                                    improved = True
                                    break
                                else:
                                    placement[g1].remove(m2)
                                    placement[g1].append(m1)
                                    placement[g2].remove(m1)
                                    placement[g2].append(m2)

                        if improved:
                            break
                    if improved:
                        break
                if improved:
                    break

            if not improved:
                break

        if current_kvpr < best_kvpr - 1e-9:
            best_kvpr = current_kvpr
            best_placement = {g: placement[g].copy() for g in range(gpu_num)}

    if best_placement is None:
        best_placement = {i: [] for i in range(gpu_num)}
        for model in models:
            best_gpu = min(range(gpu_num), key=lambda g: sum(m.model_size for m in best_placement[g]))
            best_placement[best_gpu].append(model)

    return best_placement

