        load = sum(m.req_rate / m.slo for m in gpu_models)
        mem = sum(m.model_size for m in gpu_models)
        if mem >= GPU_MEMORY:
            return float('inf')
        if GPU_MEMORY - mem <= 1e-12:
            return float('inf')
        return load / (GPU_MEMORY - mem)

    def max_kvpr(placement):
        max_val = 0.0
        for g in range(gpu_num):
            val = kvpr_for_gpu(placement.get(g, []))
            if val > max_val:
                max_val = val
        return max_val

    best_placement = None
    best_value = float('inf')

    for _ in range(30):
        placement = {i: [] for i in range(gpu_num)}
        mem_used = [0] * gpu_num

        shuffled = list(models)
        random.shuffle(shuffled)

        for model in shuffled:
            best_gpu = -1
            best_score = float('inf')

            for g in range(gpu_num):
                if mem_used[g] + model.model_size <= GPU_MEMORY:
                    placement[g].append(model)
                    temp_score = kvpr_for_gpu(placement[g])
                    placement[g].pop()

                    if temp_score < best_score:
                        best_score = temp_score
                        best_gpu = g

            if best_gpu == -1:
                best_gpu = max(range(gpu_num), key=lambda g: GPU_MEMORY - mem_used[g])

            placement[best_gpu].append(model)
            mem_used[best_gpu] += model.model_size

        current_value = max_kvpr(placement)

        for _ in range(150):
            improved = False

            kvprs = [kvpr_for_gpu(placement[g]) for g in range(gpu_num)]
            worst_gpu = max(range(gpu_num), key=lambda g: kvprs[g])

            if not placement[worst_gpu]:
                continue

            for model in list(placement[worst_gpu]):
                for target in range(gpu_num):
                    if target == worst_gpu:
                        continue
                    if mem_used[target] + model.model_size <= GPU_MEMORY:
                        placement[worst_gpu].remove(model)
                        placement[target].append(model)

                        new_kvprs = [kvpr_for_gpu(placement[g]) for g in range(gpu_num)]
                        new_max = max(new_kvprs)

                        if new_max < current_value:
                            mem_used[worst_gpu] -= model.model_size
                            mem_used[target] += model.model_size
                            current_value = new_max
                            improved = True
                            break
                        else:
                            placement[target].remove(model)
                            placement[worst_gpu].append(model)

                if improved:
                    break

            if improved:
                continue

            for i in range(gpu_num):
                for j in range(i + 1, gpu_num):
                    for model_i in list(placement[i]):
                        for model_j in list(placement[j]):
                            if (mem_used[i] - model_i.model_size + model_j.model_size <= GPU_MEMORY and
                                mem_used[j] - model_j.model_size + model_i.model_size <= GPU_MEMORY):

                                placement[i].remove(model_i)
                                placement[i].append(model_j)
                                placement[j].remove(model_j)
                                placement[j].append(model_i)

                                new_kvprs = [kvpr_for_gpu(placement[g]) for g in range(gpu_num)]
                                new_max = max(new_kvprs)

                                if new_max < current_value:
                                    mem_used[i] = mem_used[i] - model_i.model_size + model_j.model_size
                                    mem_used[j] = mem_used[j] - model_j.model_size + model_i.model_size
                                    current_value = new_max
                                    improved = True
                                    break
                                else:
                                    placement[i].remove(model_j)
                                    placement[i].append(model_i)
                                    placement[j].remove(model_i)
                                    placement[j].append(model_j)

                        if improved:
                            break
                    if improved:
                        break
                if improved:
                    break

            if not improved:
                break

        if current_value < best_value:
            best_value = current_value
            best_placement = {g: list(placement[g]) for g in range(gpu_num)}

    if best_placement is None:
        best_placement = {i: [] for i in range(gpu_num)}
        for model in models:
            gpu_id = min(range(gpu_num), key=lambda g: sum(m.model_size for m in best_placement[g]))
            best_placement[gpu_id].append(model)

    return best_placement

def compute_model_placement(gpu_num, models):
    GPU_MEMORY_LIMIT = 80

    def calculate_kvpr(gpu_models):
        if not gpu_models:
            return 0
        total_load = sum(m.req_rate / m.slo for m in gpu_models)
        total_size = sum(m.model_size for m in gpu_models)
        if total_size >= GPU_MEMORY_LIMIT:
            return float('inf')
        return total_load / (GPU_MEMORY_LIMIT - total_size)

    def calculate_max_kvpr(placement):
        return max(calculate_kvpr(placement[i]) for i in range(gpu_num))

    # Precompute model info
    model_info = []
    for i, m in enumerate(models):
        model_info.append({
            'id': i,
            'model': m,
            'size': m.model_size,
            'load': m.req_rate / m.slo if m.slo > 0 else 0,
            'density': (m.req_rate / m.slo if m.slo > 0 else 0) / m.model_size if m.model_size > 0 else float('inf')
        })

    best_placement = None
    best_max_kvpr = float('inf')

    # Multi-start greedy approach with local search
    for start in range(max(30, gpu_num * 5)):
        import random
        random.shuffle(model_info)

        placement = {i: [] for i in range(gpu_num)}
        gpu_mem = [0] * gpu_num
        gpu_load = [0.0] * gpu_num

        # Greedy assignment based on model density
        for info in model_info:
            best_gpu = -1
            min_potential_max = float('inf')

            # Find the best GPU to place the model
            for gpu_id in range(gpu_num):
                if gpu_mem[gpu_id] + info['size'] <= GPU_MEMORY_LIMIT:
                    temp_mem = gpu_mem[gpu_id] + info['size']
                    temp_load = gpu_load[gpu_id] + info['load']
                    temp_placement = {k: list(placement[k]) for k in range(gpu_num)}
                    temp_placement[gpu_id].append(info['model'])
                    temp_max_kvpr = calculate_max_kvpr(temp_placement)

                    if temp_max_kvpr < min_potential_max:
                        min_potential_max = temp_max_kvpr
                        best_gpu = gpu_id

            # If no good GPU found, place in GPU with most free space
            if best_gpu == -1:
                free_space = [GPU_MEMORY_LIMIT - gpu_mem[g] for g in range(gpu_num)]
                best_gpu = max(range(gpu_num), key=lambda g: free_space[g])
                if gpu_mem[best_gpu] + info['size'] > GPU_MEMORY_LIMIT:
                    continue

            placement[best_gpu].append(info['model'])
            gpu_mem[best_gpu] += info['size']
            gpu_load[best_gpu] += info['load']

        # Local search: try to improve by swapping
        improved = True
        max_iterations = 50
        iterations = 0

        while improved and iterations < max_iterations:
            improved = False
            iterations += 1

            # Try all pairs of models from different GPUs
            for i in range(gpu_num):
                for j in range(gpu_num):
                    if i == j:
                        continue
                    for mi, model_i in enumerate(placement[i]):
                        for mj, model_j in enumerate(placement[j]):
                            # Calculate potential swap effect
                            new_mem_i = gpu_mem[i] - model_i.model_size + model_j.model_size
                            new_mem_j = gpu_mem[j] - model_j.model_size + model_i.model_size

                            if new_mem_i > GPU_MEMORY_LIMIT or new_mem_j > GPU_MEMORY_LIMIT:
                                continue

                            new_load_i = gpu_load[i] - model_i.req_rate / model_i.slo + model_j.req_rate / model_j.slo
                            new_load_j = gpu_load[j] - model_j.req_rate / model_j.slo + model_i.req_rate / model_i.slo

                            # Calculate new max KVPR after swap
                            temp_placement = {k: list(placement[k]) for k in range(gpu_num)}
                            temp_placement[i][mi] = model_j
                            temp_placement[j][mj] = model_i

                            new_max_kvpr = calculate_max_kvpr(temp_placement)
                            old_max_kvpr = calculate_max_kvpr(placement)

                            if new_max_kvpr < old_max_kvpr - 1e-9:
                                placement = temp_placement
                                gpu_mem[i] = new_mem_i
                                gpu_mem[j] = new_mem_j
                                gpu_load[i] = new_load_i
                                gpu_load[j] = new_load_j
                                improved = True
                                break
                        if improved:
                            break
                    if improved:
                        break

        # Update best solution
        current_max_kvpr = calculate_max_kvpr(placement)
        if current_max_kvpr < best_max_kvpr - 1e-9:
            best_max_kvpr = current_max_kvpr
            best_placement = {i: list(placement[i]) for i in range(gpu_num)}

    # Fallback solution if no good solution found
    if best_placement is None:
        best_placement = {i: [] for i in range(gpu_num)}
        gpu_mem = [0] * gpu_num
        for m in models:
            best_gpu = min(range(gpu_num), key=lambda g: gpu_mem[g])
            if gpu_mem[best_gpu] + m.model_size <= GPU_MEMORY_LIMIT:
                best_placement[best_gpu].append(m)
                gpu_mem[best_gpu] += m.model_size

    return best_placement

import math
