def compute_model_placement(gpu_num, models):
    GPU_MEMORY_LIMIT = 80

    # Assign unique IDs to models for tracking
    for idx, model in enumerate(models):
        model.id = idx

    def kvpr_for_gpu(gpu_models):
        if not gpu_models:
            return 0
        load = sum(m.req_rate / m.slo for m in gpu_models)
        mem = sum(m.model_size for m in gpu_models)
        if mem >= GPU_MEMORY_LIMIT:
            return float('inf')
        return load / (GPU_MEMORY_LIMIT - mem)

    def max_kvpr(placement):
        max_val = 0
        for i in range(gpu_num):
            val = kvpr_for_gpu(placement[i])
            if val > max_val:
                max_val = val
        return max_val

    best_placement = None
    best_kvpr = float('inf')

    for attempt in range(30):
        # Initialize placement
        placement = {i: [] for i in range(gpu_num)}
        gpu_mem = [0] * gpu_num
        unassigned = models[:]
        random.shuffle(unassigned)

        # First-fit with lookahead scoring
        while unassigned:
            model = unassigned[0]
            best_gpu = -1
            best_score = float('inf')

            for gid in range(gpu_num):
                if gpu_mem[gid] + model.model_size <= GPU_MEMORY_LIMIT:
                    # Temporarily add model
                    placement[gid].append(model)
                    gpu_mem[gid] += model.model_size
                    # Compute score
                    score = max_kvpr(placement)
                    # Remove model
                    placement[gid].pop()
                    gpu_mem[gid] -= model.model_size

                    if score < best_score:
                        best_score = score
                        best_gpu = gid

            # If no GPU can fit, find one with minimal memory
            if best_gpu == -1:
                best_gpu = min(range(gpu_num), key=lambda g: gpu_mem[g])
                # Check if we can swap to make room
                for gid in range(gpu_num):
                    if gpu_mem[gid] + model.model_size <= GPU_MEMORY_LIMIT:
                        best_gpu = gid
                        break

            placement[best_gpu].append(model)
            gpu_mem[best_gpu] += model.model_size
            unassigned.remove(model)

        current_kvpr = max_kvpr(placement)

        # Local search: try swaps
        improved = True
        iteration = 0
        while improved and iteration < 50:
            improved = False
            iteration += 1

            for i in range(gpu_num):
                for j in range(i+1, gpu_num):
                    # Try all pairwise swaps
                    for mi, model_i in enumerate(placement[i]):
                        for mj, model_j in enumerate(placement[j]):
                            # Check memory constraints
                            new_mem_i = gpu_mem[i] - model_i.model_size + model_j.model_size
                            new_mem_j = gpu_mem[j] - model_j.model_size + model_i.model_size

                            if new_mem_i > GPU_MEMORY_LIMIT or new_mem_j > GPU_MEMORY_LIMIT:
                                continue

                            # Perform swap
                            placement[i][mi], placement[j][mj] = placement[j][mj], placement[i][mi]
                            gpu_mem[i] = new_mem_i
                            gpu_mem[j] = new_mem_j

                            new_kvpr = max_kvpr(placement)

                            if new_kvpr < current_kvpr:
                                current_kvpr = new_kvpr
                                improved = True
                                break
                            else:
                                # Revert swap
                                placement[i][mi], placement[j][mj] = placement[j][mj], placement[i][mi]
                                gpu_mem[i] = gpu_mem[i] - model_j.model_size + model_i.model_size
                                gpu_mem[j] = gpu_mem[j] - model_i.model_size + model_j.model_size

                        if improved:
                            break
                    if improved:
                        break
                if improved:
                    break

        # Also try moving single models
        improved = True
        while improved:
            improved = False
            for i in range(gpu_num):
                for j in range(gpu_num):
                    if i == j:
                        continue
                    for mi, model in enumerate(placement[i]):
                        if gpu_mem[j] + model.model_size <= GPU_MEMORY_LIMIT:
                            # Try move
                            placement[i].pop(mi)
                            placement[j].append(model)
                            gpu_mem[i] -= model.model_size
                            gpu_mem[j] += model.model_size

                            new_kvpr = max_kvpr(placement)

                            if new_kvpr < current_kvpr:
                                current_kvpr = new_kvpr
                                improved = True
                                break
                            else:
                                # Revert move
                                placement[j].remove(model)
                                placement[i].insert(mi, model)
                                gpu_mem[i] += model.model_size
                                gpu_mem[j] -= model.model_size

                    if improved:
                        break
                if improved:
                    break

        if current_kvpr < best_kvpr:
            best_kvpr = current_kvpr
            best_placement = {i: list(placement[i]) for i in range(gpu_num)}

    # Fallback: simple bin packing if no valid placement found
    if best_placement is None:
        best_placement = {i: [] for i in range(gpu_num)}
        gpu_mem = [0] * gpu_num
        for model in models:
            # Find GPU with most free space
            best_gpu = max(range(gpu_num), key=lambda g: GPU_MEMORY_LIMIT - gpu_mem[g])
            best_placement[best_gpu].append(model)
            gpu_mem[best_gpu] += model.model_size

    # Remove temporary IDs
    for model in models:
        if hasattr(model, 'id'):
            delattr(model, 'id')

    return best_placement
